        std::vector<int> c(r + 1, 0);
        for (int x : v) c[x - mn]++;
        auto it = v.begin();
        for (int j = 0; j <= r; j++)
            if (int k = c[j]) it = std::fill_n(it, k, j + mn);
        return;
    }
    if (i * 4 > n || n - i < 80) {
        std::sort(v.begin() + i, v.end());
        if (v[i] < v[i-1]) std::inplace_merge(v.begin(), v.begin() + i, v.end());
